import{_ as s,c as a,a as e,o as t}from"./app-DRoh6aWd.js";const p={};function l(c,n){return t(),a("div",null,[...n[0]||(n[0]=[e(`<h1 id="react-server-components-rsc-学习笔记" tabindex="-1"><a class="header-anchor" href="#react-server-components-rsc-学习笔记"><span>React Server Components（RSC）学习笔记</span></a></h1><h2 id="_1-rsc-是什么" tabindex="-1"><a class="header-anchor" href="#_1-rsc-是什么"><span>1. RSC 是什么？</span></a></h2><p>RSC，全称是 <strong>React Server Components</strong>，中文可以理解为 <strong>React 服务端组件</strong>。</p><p>它是 React 提供的一种新的组件模型：</p><blockquote><p>有些组件可以只在服务器上运行，不会把对应的 JavaScript 代码发送到浏览器。</p></blockquote><p>传统 React 组件通常会被打包成 JS，发送到浏览器运行；而 RSC 允许一部分组件只在服务端执行，最后把渲染结果传给客户端。</p><p>简单理解：</p><div class="language-txt line-numbers-mode" data-highlighter="prismjs" data-ext="txt"><pre><code class="language-txt"><span class="line">普通 React 组件：</span>
<span class="line">组件代码 -&gt; 打包成 JS -&gt; 浏览器执行 -&gt; 渲染页面</span>
<span class="line"></span>
<span class="line">React Server Component：</span>
<span class="line">组件代码 -&gt; 服务端执行 -&gt; 生成结果 -&gt; 发送给浏览器显示</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_2-为什么需要-rsc" tabindex="-1"><a class="header-anchor" href="#_2-为什么需要-rsc"><span>2. 为什么需要 RSC？</span></a></h2><p>前端项目变大以后，经常会遇到几个问题：</p><ol><li>首屏 JS 包太大</li><li>浏览器需要下载、解析、执行大量 JS</li><li>数据请求逻辑分散在客户端</li><li>有些代码其实没必要发给浏览器，比如数据库查询、文件读取、后端 SDK 调用</li></ol><p>RSC 的核心目标是：</p><blockquote><p>把不需要在浏览器运行的代码留在服务器，减少客户端负担。</p></blockquote><h2 id="_3-rsc-解决了什么问题" tabindex="-1"><a class="header-anchor" href="#_3-rsc-解决了什么问题"><span>3. RSC 解决了什么问题？</span></a></h2><h3 id="_3-1-减少客户端-javascript-体积" tabindex="-1"><a class="header-anchor" href="#_3-1-减少客户端-javascript-体积"><span>3.1 减少客户端 JavaScript 体积</span></a></h3><p>如果一个组件是 Server Component，它的组件代码不会进入客户端 JS bundle。</p><p>例如：</p><div class="language-tsx line-numbers-mode" data-highlighter="prismjs" data-ext="tsx"><pre><code class="language-tsx"><span class="line"><span class="token keyword">async</span> <span class="token keyword">function</span> <span class="token function">ArticleList</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">const</span> articles <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token function">getArticles</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">  <span class="token keyword">return</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>ul</span><span class="token punctuation">&gt;</span></span><span class="token plain-text"></span>
<span class="line">      </span><span class="token punctuation">{</span>articles<span class="token punctuation">.</span><span class="token function">map</span><span class="token punctuation">(</span>article <span class="token operator">=&gt;</span> <span class="token punctuation">(</span></span>
<span class="line">        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>li</span> <span class="token attr-name">key</span><span class="token script language-javascript"><span class="token script-punctuation punctuation">=</span><span class="token punctuation">{</span>article<span class="token punctuation">.</span>id<span class="token punctuation">}</span></span><span class="token punctuation">&gt;</span></span><span class="token punctuation">{</span>article<span class="token punctuation">.</span>title<span class="token punctuation">}</span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>li</span><span class="token punctuation">&gt;</span></span></span>
<span class="line">      <span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">}</span><span class="token plain-text"></span>
<span class="line">    </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>ul</span><span class="token punctuation">&gt;</span></span></span>
<span class="line">  <span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果这个组件只负责查询数据并渲染列表，不需要点击事件、状态、浏览器 API，那么它就适合做 Server Component。</p><h3 id="_3-2-更接近后端的数据获取方式" tabindex="-1"><a class="header-anchor" href="#_3-2-更接近后端的数据获取方式"><span>3.2 更接近后端的数据获取方式</span></a></h3><p>在 RSC 中，可以直接在组件里写异步数据获取：</p><div class="language-tsx line-numbers-mode" data-highlighter="prismjs" data-ext="tsx"><pre><code class="language-tsx"><span class="line"><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token keyword">async</span> <span class="token keyword">function</span> <span class="token function">Page</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">const</span> user <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token function">getUser</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">  <span class="token keyword">return</span> <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">{</span>user<span class="token punctuation">.</span>name<span class="token punctuation">}</span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这和传统客户端组件不一样。</p><p>传统客户端组件常见写法：</p><div class="language-tsx line-numbers-mode" data-highlighter="prismjs" data-ext="tsx"><pre><code class="language-tsx"><span class="line"><span class="token function">useEffect</span><span class="token punctuation">(</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token function">fetch</span><span class="token punctuation">(</span><span class="token string">&#39;/api/user&#39;</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">.</span><span class="token function">then</span><span class="token punctuation">(</span>res <span class="token operator">=&gt;</span> res<span class="token punctuation">.</span><span class="token function">json</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">.</span><span class="token function">then</span><span class="token punctuation">(</span>data <span class="token operator">=&gt;</span> <span class="token function">setUser</span><span class="token punctuation">(</span>data<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>RSC 可以让数据在服务端提前准备好，再把结果传给页面。</p><h3 id="_3-3-可以安全使用服务端能力" tabindex="-1"><a class="header-anchor" href="#_3-3-可以安全使用服务端能力"><span>3.3 可以安全使用服务端能力</span></a></h3><p>Server Component 可以访问服务端资源，例如：</p><ul><li>数据库</li><li>文件系统</li><li>后端环境变量</li><li>私有 API key</li><li>服务端 SDK</li></ul><p>例如：</p><div class="language-tsx line-numbers-mode" data-highlighter="prismjs" data-ext="tsx"><pre><code class="language-tsx"><span class="line"><span class="token keyword">import</span> <span class="token punctuation">{</span> db <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;@/lib/db&#39;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token keyword">async</span> <span class="token keyword">function</span> <span class="token function">ProductPage</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">const</span> products <span class="token operator">=</span> <span class="token keyword">await</span> db<span class="token punctuation">.</span>product<span class="token punctuation">.</span><span class="token function">findMany</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">  <span class="token keyword">return</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span><span class="token punctuation">&gt;</span></span><span class="token plain-text"></span>
<span class="line">      </span><span class="token punctuation">{</span>products<span class="token punctuation">.</span><span class="token function">map</span><span class="token punctuation">(</span>product <span class="token operator">=&gt;</span> <span class="token punctuation">(</span></span>
<span class="line">        <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span> <span class="token attr-name">key</span><span class="token script language-javascript"><span class="token script-punctuation punctuation">=</span><span class="token punctuation">{</span>product<span class="token punctuation">.</span>id<span class="token punctuation">}</span></span><span class="token punctuation">&gt;</span></span><span class="token punctuation">{</span>product<span class="token punctuation">.</span>name<span class="token punctuation">}</span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>p</span><span class="token punctuation">&gt;</span></span></span>
<span class="line">      <span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">}</span><span class="token plain-text"></span>
<span class="line">    </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span></span>
<span class="line">  <span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这类代码不应该放到浏览器中执行，因为数据库连接和私钥都不能暴露给前端。</p><h2 id="_4-rsc-和-ssr-的区别" tabindex="-1"><a class="header-anchor" href="#_4-rsc-和-ssr-的区别"><span>4. RSC 和 SSR 的区别</span></a></h2><p>RSC 很容易和 SSR 混淆。</p><h3 id="_4-1-ssr-是什么" tabindex="-1"><a class="header-anchor" href="#_4-1-ssr-是什么"><span>4.1 SSR 是什么？</span></a></h3><p>SSR，全称是 <strong>Server Side Rendering</strong>，服务端渲染。</p><p>SSR 的重点是：</p><blockquote><p>在服务端生成 HTML，让浏览器更快看到页面内容。</p></blockquote><p>流程大致是：</p><div class="language-txt line-numbers-mode" data-highlighter="prismjs" data-ext="txt"><pre><code class="language-txt"><span class="line">用户访问页面 -&gt; 服务端运行 React -&gt; 生成 HTML -&gt; 浏览器显示 HTML -&gt; 浏览器下载 JS -&gt; hydrate 激活交互</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="_4-2-rsc-是什么" tabindex="-1"><a class="header-anchor" href="#_4-2-rsc-是什么"><span>4.2 RSC 是什么？</span></a></h3><p>RSC 的重点是：</p><blockquote><p>让一部分 React 组件只在服务端运行，不发送组件 JS 到浏览器。</p></blockquote><p>RSC 不只是生成 HTML，它改变的是组件的运行位置和打包方式。</p><h3 id="_4-3-对比总结" tabindex="-1"><a class="header-anchor" href="#_4-3-对比总结"><span>4.3 对比总结</span></a></h3><table><thead><tr><th>对比项</th><th>SSR</th><th>RSC</th></tr></thead><tbody><tr><td>核心目标</td><td>服务端生成 HTML</td><td>组件只在服务端运行</td></tr><tr><td>是否减少客户端组件 JS</td><td>不一定</td><td>是</td></tr><tr><td>是否需要 hydration</td><td>通常需要</td><td>Server Component 本身不需要</td></tr><tr><td>关注点</td><td>页面首屏渲染</td><td>组件运行位置和数据获取</td></tr><tr><td>常见场景</td><td>提升首屏和 SEO</td><td>减少 JS、服务端数据查询</td></tr></tbody></table><p>一句话区分：</p><blockquote><p>SSR 关注“HTML 在哪里生成”，RSC 关注“组件代码在哪里运行”。</p></blockquote><h2 id="_5-server-component-和-client-component" tabindex="-1"><a class="header-anchor" href="#_5-server-component-和-client-component"><span>5. Server Component 和 Client Component</span></a></h2><p>在支持 RSC 的框架中，组件通常分为两类：</p><ol><li>Server Component</li><li>Client Component</li></ol><h2 id="_5-1-server-component" tabindex="-1"><a class="header-anchor" href="#_5-1-server-component"><span>5.1 Server Component</span></a></h2><p>Server Component 运行在服务器上。</p><p>特点：</p><ul><li>默认不发送 JS 到浏览器</li><li>可以直接访问数据库、文件系统、服务端环境变量</li><li>可以使用 async/await 获取数据</li><li>不能使用浏览器事件</li><li>不能使用 useState、useEffect 等客户端 Hook</li><li>不能访问 window、document、localStorage</li></ul><p>适合场景：</p><ul><li>页面主体结构</li><li>数据列表展示</li><li>文章详情</li><li>商品详情</li><li>静态内容</li><li>服务端数据查询</li></ul><p>示例：</p><div class="language-tsx line-numbers-mode" data-highlighter="prismjs" data-ext="tsx"><pre><code class="language-tsx"><span class="line"><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token keyword">async</span> <span class="token keyword">function</span> <span class="token function">ArticlePage</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">const</span> article <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token function">getArticle</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">  <span class="token keyword">return</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>article</span><span class="token punctuation">&gt;</span></span><span class="token plain-text"></span>
<span class="line">      </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>h1</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">{</span>article<span class="token punctuation">.</span>title<span class="token punctuation">}</span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>h1</span><span class="token punctuation">&gt;</span></span><span class="token plain-text"></span>
<span class="line">      </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">{</span>article<span class="token punctuation">.</span>content<span class="token punctuation">}</span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>p</span><span class="token punctuation">&gt;</span></span><span class="token plain-text"></span>
<span class="line">    </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>article</span><span class="token punctuation">&gt;</span></span></span>
<span class="line">  <span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_5-2-client-component" tabindex="-1"><a class="header-anchor" href="#_5-2-client-component"><span>5.2 Client Component</span></a></h2><p>Client Component 会发送到浏览器运行。</p><p>在 Next.js App Router 中，需要在文件顶部写：</p><div class="language-tsx line-numbers-mode" data-highlighter="prismjs" data-ext="tsx"><pre><code class="language-tsx"><span class="line"><span class="token string">&#39;use client&#39;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>示例：</p><div class="language-tsx line-numbers-mode" data-highlighter="prismjs" data-ext="tsx"><pre><code class="language-tsx"><span class="line"><span class="token string">&#39;use client&#39;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">import</span> <span class="token punctuation">{</span> useState <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;react&#39;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token keyword">function</span> <span class="token function">Counter</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">const</span> <span class="token punctuation">[</span>count<span class="token punctuation">,</span> setCount<span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token function">useState</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">  <span class="token keyword">return</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>button</span> <span class="token attr-name">onClick</span><span class="token script language-javascript"><span class="token script-punctuation punctuation">=</span><span class="token punctuation">{</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token function">setCount</span><span class="token punctuation">(</span>count <span class="token operator">+</span> <span class="token number">1</span><span class="token punctuation">)</span><span class="token punctuation">}</span></span><span class="token punctuation">&gt;</span></span><span class="token plain-text"></span>
<span class="line">      </span><span class="token punctuation">{</span>count<span class="token punctuation">}</span><span class="token plain-text"></span>
<span class="line">    </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>button</span><span class="token punctuation">&gt;</span></span></span>
<span class="line">  <span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>特点：</p><ul><li>可以使用 useState、useEffect</li><li>可以绑定点击事件、输入事件</li><li>可以访问 window、document、localStorage</li><li>会增加客户端 JS 体积</li></ul><p>适合场景：</p><ul><li>按钮点击</li><li>表单交互</li><li>弹窗</li><li>Tabs 切换</li><li>下拉菜单</li><li>拖拽</li><li>富文本编辑器</li><li>依赖浏览器 API 的功能</li></ul><h2 id="_6-use-client-的作用" tabindex="-1"><a class="header-anchor" href="#_6-use-client-的作用"><span>6. <code>&#39;use client&#39;</code> 的作用</span></a></h2><p><code>&#39;use client&#39;</code> 用来声明一个文件是 Client Component 的入口。</p><div class="language-tsx line-numbers-mode" data-highlighter="prismjs" data-ext="tsx"><pre><code class="language-tsx"><span class="line"><span class="token string">&#39;use client&#39;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token keyword">function</span> <span class="token function">SearchBox</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">return</span> <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>input</span> <span class="token attr-name">placeholder</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>搜索<span class="token punctuation">&quot;</span></span> <span class="token punctuation">/&gt;</span></span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>注意：</p><blockquote><p>一旦某个文件写了 <code>&#39;use client&#39;</code>，它导入的子组件也会进入客户端组件树。</p></blockquote><p>所以不要随便在很大的组件顶部写 <code>&#39;use client&#39;</code>。</p><p>推荐做法：</p><div class="language-txt line-numbers-mode" data-highlighter="prismjs" data-ext="txt"><pre><code class="language-txt"><span class="line">页面整体：Server Component</span>
<span class="line">局部交互：Client Component</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>例如：</p><div class="language-tsx line-numbers-mode" data-highlighter="prismjs" data-ext="tsx"><pre><code class="language-tsx"><span class="line"><span class="token comment">// app/page.tsx，Server Component</span></span>
<span class="line"><span class="token keyword">import</span> SearchBox <span class="token keyword">from</span> <span class="token string">&#39;./SearchBox&#39;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token keyword">async</span> <span class="token keyword">function</span> <span class="token function">Page</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">const</span> articles <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token function">getArticles</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">  <span class="token keyword">return</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>main</span><span class="token punctuation">&gt;</span></span><span class="token plain-text"></span>
<span class="line">      </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span><span class="token class-name">SearchBox</span></span> <span class="token punctuation">/&gt;</span></span><span class="token plain-text"></span>
<span class="line">      </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span><span class="token class-name">ArticleList</span></span> <span class="token attr-name">articles</span><span class="token script language-javascript"><span class="token script-punctuation punctuation">=</span><span class="token punctuation">{</span>articles<span class="token punctuation">}</span></span> <span class="token punctuation">/&gt;</span></span><span class="token plain-text"></span>
<span class="line">    </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>main</span><span class="token punctuation">&gt;</span></span></span>
<span class="line">  <span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-tsx line-numbers-mode" data-highlighter="prismjs" data-ext="tsx"><pre><code class="language-tsx"><span class="line"><span class="token comment">// app/SearchBox.tsx，Client Component</span></span>
<span class="line"><span class="token string">&#39;use client&#39;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">import</span> <span class="token punctuation">{</span> useState <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;react&#39;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token keyword">function</span> <span class="token function">SearchBox</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">const</span> <span class="token punctuation">[</span>keyword<span class="token punctuation">,</span> setKeyword<span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token function">useState</span><span class="token punctuation">(</span><span class="token string">&#39;&#39;</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">  <span class="token keyword">return</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>input</span></span>
<span class="line">      <span class="token attr-name">value</span><span class="token script language-javascript"><span class="token script-punctuation punctuation">=</span><span class="token punctuation">{</span>keyword<span class="token punctuation">}</span></span></span>
<span class="line">      <span class="token attr-name">onChange</span><span class="token script language-javascript"><span class="token script-punctuation punctuation">=</span><span class="token punctuation">{</span>e <span class="token operator">=&gt;</span> <span class="token function">setKeyword</span><span class="token punctuation">(</span>e<span class="token punctuation">.</span>target<span class="token punctuation">.</span>value<span class="token punctuation">)</span><span class="token punctuation">}</span></span></span>
<span class="line">    <span class="token punctuation">/&gt;</span></span></span>
<span class="line">  <span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_7-rsc-中的数据传递规则" tabindex="-1"><a class="header-anchor" href="#_7-rsc-中的数据传递规则"><span>7. RSC 中的数据传递规则</span></a></h2><p>Server Component 可以把数据传给 Client Component。</p><div class="language-tsx line-numbers-mode" data-highlighter="prismjs" data-ext="tsx"><pre><code class="language-tsx"><span class="line"><span class="token comment">// Server Component</span></span>
<span class="line"><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token keyword">async</span> <span class="token keyword">function</span> <span class="token function">Page</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">const</span> user <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token function">getUser</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">  <span class="token keyword">return</span> <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span><span class="token class-name">UserCard</span></span> <span class="token attr-name">user</span><span class="token script language-javascript"><span class="token script-punctuation punctuation">=</span><span class="token punctuation">{</span>user<span class="token punctuation">}</span></span> <span class="token punctuation">/&gt;</span></span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language-tsx line-numbers-mode" data-highlighter="prismjs" data-ext="tsx"><pre><code class="language-tsx"><span class="line"><span class="token string">&#39;use client&#39;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token keyword">function</span> <span class="token function">UserCard</span><span class="token punctuation">(</span><span class="token punctuation">{</span> user <span class="token punctuation">}</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">return</span> <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>div</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">{</span>user<span class="token punctuation">.</span>name<span class="token punctuation">}</span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>div</span><span class="token punctuation">&gt;</span></span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>但是传递的数据必须是可以序列化的。</p><p>可以传：</p><ul><li>string、number、boolean、null、undefined</li><li>普通对象、数组</li><li>Date、Map、Set、BigInt、Promise（React 的 RSC 序列化支持这些）</li><li>用 <code>&#39;use server&#39;</code> 标记的服务端函数（Server Actions）</li></ul><p>不能传：</p><ul><li>普通函数（未标记 <code>&#39;use server&#39;</code> 的函数无法序列化）</li><li>class 实例（带方法/原型的对象）</li><li>数据库连接、文件句柄等服务端专属对象</li><li>Symbol</li></ul><p>错误理解：</p><div class="language-tsx line-numbers-mode" data-highlighter="prismjs" data-ext="tsx"><pre><code class="language-tsx"><span class="line"><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span><span class="token class-name">ClientButton</span></span> <span class="token attr-name">onClick</span><span class="token script language-javascript"><span class="token script-punctuation punctuation">=</span><span class="token punctuation">{</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token builtin">console</span><span class="token punctuation">.</span><span class="token function">log</span><span class="token punctuation">(</span><span class="token string">&#39;click&#39;</span><span class="token punctuation">)</span><span class="token punctuation">}</span></span> <span class="token punctuation">/&gt;</span></span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>如果 <code>onClick</code> 是从 Server Component 传给 Client Component 的普通函数，这通常是不允许的。</p><p>因为函数不能从服务器序列化传到浏览器。</p><h2 id="_8-server-component-能不能导入-client-component" tabindex="-1"><a class="header-anchor" href="#_8-server-component-能不能导入-client-component"><span>8. Server Component 能不能导入 Client Component？</span></a></h2><p>可以。</p><p>常见结构就是：</p><div class="language-txt line-numbers-mode" data-highlighter="prismjs" data-ext="txt"><pre><code class="language-txt"><span class="line">Server Component</span>
<span class="line">  ├── Client Component</span>
<span class="line">  └── Server Component</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>例如：</p><div class="language-tsx line-numbers-mode" data-highlighter="prismjs" data-ext="tsx"><pre><code class="language-tsx"><span class="line"><span class="token comment">// Server Component</span></span>
<span class="line"><span class="token keyword">import</span> LikeButton <span class="token keyword">from</span> <span class="token string">&#39;./LikeButton&#39;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token keyword">async</span> <span class="token keyword">function</span> <span class="token function">ArticlePage</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">const</span> article <span class="token operator">=</span> <span class="token keyword">await</span> <span class="token function">getArticle</span><span class="token punctuation">(</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">  <span class="token keyword">return</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>article</span><span class="token punctuation">&gt;</span></span><span class="token plain-text"></span>
<span class="line">      </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>h1</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">{</span>article<span class="token punctuation">.</span>title<span class="token punctuation">}</span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>h1</span><span class="token punctuation">&gt;</span></span><span class="token plain-text"></span>
<span class="line">      </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span><span class="token class-name">LikeButton</span></span> <span class="token attr-name">articleId</span><span class="token script language-javascript"><span class="token script-punctuation punctuation">=</span><span class="token punctuation">{</span>article<span class="token punctuation">.</span>id<span class="token punctuation">}</span></span> <span class="token punctuation">/&gt;</span></span><span class="token plain-text"></span>
<span class="line">    </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>article</span><span class="token punctuation">&gt;</span></span></span>
<span class="line">  <span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><code>LikeButton</code> 负责交互，所以它是 Client Component。</p><h2 id="_9-client-component-能不能导入-server-component" tabindex="-1"><a class="header-anchor" href="#_9-client-component-能不能导入-server-component"><span>9. Client Component 能不能导入 Server Component？</span></a></h2><p>一般不应该直接导入。</p><p>因为 Client Component 会在浏览器运行，如果它直接导入 Server Component，就可能把服务端逻辑带到客户端边界里。</p><p>推荐方式是：</p><blockquote><p>在 Server Component 中组合好结构，把 Client Component 放进去。</p></blockquote><p>例如：</p><div class="language-tsx line-numbers-mode" data-highlighter="prismjs" data-ext="tsx"><pre><code class="language-tsx"><span class="line"><span class="token comment">// Server Component</span></span>
<span class="line"><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token keyword">function</span> <span class="token function">Page</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">return</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span><span class="token class-name">ClientLayout</span></span><span class="token punctuation">&gt;</span></span><span class="token plain-text"></span>
<span class="line">      </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span><span class="token class-name">ServerContent</span></span> <span class="token punctuation">/&gt;</span></span><span class="token plain-text"></span>
<span class="line">    </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span><span class="token class-name">ClientLayout</span></span><span class="token punctuation">&gt;</span></span></span>
<span class="line">  <span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>这种方式是服务端先组合好 children，再把可交互部分交给客户端。</p><h2 id="_10-rsc-和-server-actions" tabindex="-1"><a class="header-anchor" href="#_10-rsc-和-server-actions"><span>10. RSC 和 Server Actions</span></a></h2><p>Server Actions 是另一种服务端能力，常和 RSC 一起出现。</p><p>Server Action 可以让表单或事件触发服务端函数。</p><p>示例：</p><div class="language-tsx line-numbers-mode" data-highlighter="prismjs" data-ext="tsx"><pre><code class="language-tsx"><span class="line"><span class="token keyword">async</span> <span class="token keyword">function</span> <span class="token function">createPost</span><span class="token punctuation">(</span>formData<span class="token operator">:</span> FormData<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token string">&#39;use server&#39;</span></span>
<span class="line"></span>
<span class="line">  <span class="token keyword">const</span> title <span class="token operator">=</span> formData<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token string">&#39;title&#39;</span><span class="token punctuation">)</span></span>
<span class="line">  <span class="token keyword">await</span> db<span class="token punctuation">.</span>post<span class="token punctuation">.</span><span class="token function">create</span><span class="token punctuation">(</span><span class="token punctuation">{</span> data<span class="token operator">:</span> <span class="token punctuation">{</span> title <span class="token punctuation">}</span> <span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token keyword">function</span> <span class="token function">Page</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">return</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>form</span> <span class="token attr-name">action</span><span class="token script language-javascript"><span class="token script-punctuation punctuation">=</span><span class="token punctuation">{</span>createPost<span class="token punctuation">}</span></span><span class="token punctuation">&gt;</span></span><span class="token plain-text"></span>
<span class="line">      </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>input</span> <span class="token attr-name">name</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>title<span class="token punctuation">&quot;</span></span> <span class="token punctuation">/&gt;</span></span><span class="token plain-text"></span>
<span class="line">      </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>button</span> <span class="token attr-name">type</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>submit<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span><span class="token plain-text">提交</span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>button</span><span class="token punctuation">&gt;</span></span><span class="token plain-text"></span>
<span class="line">    </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>form</span><span class="token punctuation">&gt;</span></span></span>
<span class="line">  <span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>理解方式：</p><ul><li>RSC 主要解决组件在哪里运行</li><li>Server Actions 主要解决用户操作如何触发服务端逻辑</li></ul><h2 id="_11-rsc-和-suspense-streaming" tabindex="-1"><a class="header-anchor" href="#_11-rsc-和-suspense-streaming"><span>11. RSC 和 Suspense / Streaming</span></a></h2><p>RSC 经常和 Suspense、流式渲染一起使用。</p><p>传统页面可能要等所有数据都准备好，才返回完整页面。</p><p>流式渲染可以让页面分块返回：</p><div class="language-tsx line-numbers-mode" data-highlighter="prismjs" data-ext="tsx"><pre><code class="language-tsx"><span class="line"><span class="token keyword">import</span> <span class="token punctuation">{</span> Suspense <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;react&#39;</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token keyword">function</span> <span class="token function">Page</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">return</span> <span class="token punctuation">(</span></span>
<span class="line">    <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>main</span><span class="token punctuation">&gt;</span></span><span class="token plain-text"></span>
<span class="line">      </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span><span class="token class-name">Header</span></span> <span class="token punctuation">/&gt;</span></span><span class="token plain-text"></span>
<span class="line">      </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span><span class="token class-name">Suspense</span></span> <span class="token attr-name">fallback</span><span class="token script language-javascript"><span class="token script-punctuation punctuation">=</span><span class="token punctuation">{</span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>p</span><span class="token punctuation">&gt;</span></span><span class="token plain-text">文章加载中...</span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>p</span><span class="token punctuation">&gt;</span></span><span class="token punctuation">}</span></span><span class="token punctuation">&gt;</span></span><span class="token plain-text"></span>
<span class="line">        </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span><span class="token class-name">ArticleList</span></span> <span class="token punctuation">/&gt;</span></span><span class="token plain-text"></span>
<span class="line">      </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span><span class="token class-name">Suspense</span></span><span class="token punctuation">&gt;</span></span><span class="token plain-text"></span>
<span class="line">    </span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>main</span><span class="token punctuation">&gt;</span></span></span>
<span class="line">  <span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>用户可以先看到 Header，再等待 ArticleList 加载完成。</p><p>好处：</p><ul><li>首屏感知速度更快</li><li>慢数据不会阻塞整个页面</li><li>用户体验更平滑</li></ul><h2 id="_12-rsc-的优势" tabindex="-1"><a class="header-anchor" href="#_12-rsc-的优势"><span>12. RSC 的优势</span></a></h2><h3 id="_12-1-更少的客户端-js" tabindex="-1"><a class="header-anchor" href="#_12-1-更少的客户端-js"><span>12.1 更少的客户端 JS</span></a></h3><p>不需要交互的组件留在服务器，浏览器少下载很多代码。</p><h3 id="_12-2-数据获取更直接" tabindex="-1"><a class="header-anchor" href="#_12-2-数据获取更直接"><span>12.2 数据获取更直接</span></a></h3><p>可以在组件中直接 await 数据。</p><h3 id="_12-3-安全性更好" tabindex="-1"><a class="header-anchor" href="#_12-3-安全性更好"><span>12.3 安全性更好</span></a></h3><p>数据库查询、私钥、后端 SDK 不会暴露给客户端。</p><h3 id="_12-4-更适合内容型页面" tabindex="-1"><a class="header-anchor" href="#_12-4-更适合内容型页面"><span>12.4 更适合内容型页面</span></a></h3><p>例如：</p><ul><li>博客</li><li>文档站</li><li>电商商品页</li><li>后台管理系统列表页</li><li>新闻资讯页面</li></ul><h2 id="_13-rsc-的限制" tabindex="-1"><a class="header-anchor" href="#_13-rsc-的限制"><span>13. RSC 的限制</span></a></h2><h3 id="_13-1-不能使用浏览器-api" tabindex="-1"><a class="header-anchor" href="#_13-1-不能使用浏览器-api"><span>13.1 不能使用浏览器 API</span></a></h3><p>Server Component 中不能写：</p><div class="language-tsx line-numbers-mode" data-highlighter="prismjs" data-ext="tsx"><pre><code class="language-tsx"><span class="line">window<span class="token punctuation">.</span>localStorage<span class="token punctuation">.</span><span class="token function">getItem</span><span class="token punctuation">(</span><span class="token string">&#39;token&#39;</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>因为服务器没有 window。</p><h3 id="_13-2-不能使用客户端状态" tabindex="-1"><a class="header-anchor" href="#_13-2-不能使用客户端状态"><span>13.2 不能使用客户端状态</span></a></h3><p>Server Component 中不能使用：</p><div class="language-tsx line-numbers-mode" data-highlighter="prismjs" data-ext="tsx"><pre><code class="language-tsx"><span class="line"><span class="token keyword">const</span> <span class="token punctuation">[</span>count<span class="token punctuation">,</span> setCount<span class="token punctuation">]</span> <span class="token operator">=</span> <span class="token function">useState</span><span class="token punctuation">(</span><span class="token number">0</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>需要交互状态时，要拆成 Client Component。</p><h3 id="_13-3-组件边界需要设计" tabindex="-1"><a class="header-anchor" href="#_13-3-组件边界需要设计"><span>13.3 组件边界需要设计</span></a></h3><p>如果随便把大组件都写成 Client Component，就失去了 RSC 的意义。</p><p>建议：</p><div class="language-txt line-numbers-mode" data-highlighter="prismjs" data-ext="txt"><pre><code class="language-txt"><span class="line">能放服务端就放服务端</span>
<span class="line">只有需要交互的局部才放客户端</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_14-常见开发思路" tabindex="-1"><a class="header-anchor" href="#_14-常见开发思路"><span>14. 常见开发思路</span></a></h2><p>设计页面时，可以按下面的顺序思考：</p><ol><li>页面哪些内容只是展示？</li><li>哪些内容需要点击、输入、拖拽、状态？</li><li>数据是否可以在服务端获取？</li><li>有没有敏感逻辑不能暴露给浏览器？</li><li>把静态展示和数据查询放 Server Component</li><li>把交互区域拆成 Client Component</li></ol><p>例如商品详情页：</p><div class="language-txt line-numbers-mode" data-highlighter="prismjs" data-ext="txt"><pre><code class="language-txt"><span class="line">商品标题、价格、描述：Server Component</span>
<span class="line">商品图片展示：Server Component 或 Client Component</span>
<span class="line">加入购物车按钮：Client Component</span>
<span class="line">评论列表：Server Component</span>
<span class="line">评论输入框：Client Component</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="_15-面试常见问题" tabindex="-1"><a class="header-anchor" href="#_15-面试常见问题"><span>15. 面试常见问题</span></a></h2><h3 id="_15-1-什么是-rsc" tabindex="-1"><a class="header-anchor" href="#_15-1-什么是-rsc"><span>15.1 什么是 RSC？</span></a></h3><p>RSC 是 React Server Components，允许 React 组件在服务器上运行，并且不把这部分组件代码发送到浏览器。它可以减少客户端 JS 体积，让数据获取更靠近服务端。</p><h3 id="_15-2-rsc-和-ssr-有什么区别" tabindex="-1"><a class="header-anchor" href="#_15-2-rsc-和-ssr-有什么区别"><span>15.2 RSC 和 SSR 有什么区别？</span></a></h3><p>SSR 关注的是服务端生成 HTML，帮助首屏更快展示；RSC 关注的是组件代码运行在服务端还是客户端。SSR 后通常还需要 hydration，而 Server Component 本身不需要在客户端 hydrate。</p><h3 id="_15-3-什么情况下应该使用-client-component" tabindex="-1"><a class="header-anchor" href="#_15-3-什么情况下应该使用-client-component"><span>15.3 什么情况下应该使用 Client Component？</span></a></h3><p>当组件需要浏览器交互或浏览器 API 时，需要使用 Client Component，比如 useState、useEffect、onClick、表单输入、localStorage、window、document 等。</p><h3 id="_15-4-server-component-可以访问数据库吗" tabindex="-1"><a class="header-anchor" href="#_15-4-server-component-可以访问数据库吗"><span>15.4 Server Component 可以访问数据库吗？</span></a></h3><p>可以。Server Component 运行在服务端，因此可以访问数据库、文件系统、服务端环境变量和后端 SDK。但这些能力不能暴露给客户端组件。</p><h3 id="_15-5-use-client-是什么意思" tabindex="-1"><a class="header-anchor" href="#_15-5-use-client-是什么意思"><span>15.5 <code>&#39;use client&#39;</code> 是什么意思？</span></a></h3><p><code>&#39;use client&#39;</code> 表示当前文件是客户端组件入口。这个组件以及它依赖的子组件会被打包到客户端 JS 中，所以应该只在确实需要交互的组件上使用。</p><h2 id="_16-学习路线" tabindex="-1"><a class="header-anchor" href="#_16-学习路线"><span>16. 学习路线</span></a></h2><p>建议学习顺序：</p><ol><li>先理解 CSR、SSR、SSG 的区别</li><li>学习 React 组件、props、state、effect</li><li>学习 Next.js App Router 的基本目录结构</li><li>理解 Server Component 和 Client Component 的区别</li><li>练习在 Server Component 中获取数据</li><li>练习把按钮、表单、弹窗拆成 Client Component</li><li>学习 Suspense、Streaming、Server Actions</li><li>做一个博客或商品列表项目巩固</li></ol><h2 id="_17-一句话总结" tabindex="-1"><a class="header-anchor" href="#_17-一句话总结"><span>17. 一句话总结</span></a></h2><p>RSC 的核心思想是：</p><blockquote><p>默认把组件放在服务器运行，只有真正需要交互的部分才交给浏览器。</p></blockquote><p>这样可以减少客户端 JS、提升性能，并让 React 更适合构建现代全栈应用。</p>`,169)])])}const o=s(p,[["render",l]]),u=JSON.parse('{"path":"/posts/React%20Server%20Components%EF%BC%88RSC%EF%BC%89%E5%AD%A6%E4%B9%A0%E7%AC%94%E8%AE%B0.html","title":"React Server Components（RSC）学习笔记","lang":"zh-CN","frontmatter":{"title":"React Server Components（RSC）学习笔记","date":"2026-06-13T00:00:00.000Z","categories":["前端开发"],"tags":["React","RSC","Next.js"]},"git":{"updatedTime":1781360145000,"contributors":[{"name":"52nnnn","username":"52nnnn","email":"2764304248@qq.com","commits":2,"url":"https://github.com/52nnnn"},{"name":"Claude Opus 4.7","username":"","email":"noreply@anthropic.com","commits":1}],"changelog":[{"hash":"61e1602c7ab5b8ecad136f49c743bdfbe872ea7e","time":1781360145000,"email":"2764304248@qq.com","author":"52nnnn","message":"docs: 全面检查并完善 26 篇学习笔记（纠错、补缺、扩充面试要点）"},{"hash":"c57369eec91b59e8a6b8c601daa934101780cab9","time":1781353152000,"email":"2764304248@qq.com","author":"52nnnn","message":"docs: 添加 RSC 和全栈框架学习笔记","coAuthors":[{"name":"Claude Opus 4.7","email":"noreply@anthropic.com"}]}]},"filePathRelative":"posts/React Server Components（RSC）学习笔记.md"}');export{o as comp,u as data};
